// ================================================
// FILTER LEADS - Find leads needing follow-up
// ================================================

const allItems = $input.all();
const now = new Date();
const leadsToFollowUp = [];

for (const item of allItems) {
  const lead = item.json;

  // Skip if no chat_id
  if (!lead.chat_id) continue;

  // Only follow up on warm and cold leads
  if (!['warm', 'cold'].includes(lead.status)) continue;

  // Skip if too many follow-ups already (max 3)
  const followUpCount = parseInt(lead.follow_up_count) || 0;
  if (followUpCount >= 3) continue;

  // Check time since last contact
  const lastContact = new Date(lead.last_contact);
  if (isNaN(lastContact.getTime())) continue;

  const hoursSinceContact = (now - lastContact) / (1000 * 60 * 60);

  // Warm leads: follow up after 24 hours
  // Cold leads: follow up after 72 hours
  const threshold = lead.status === 'warm' ? 24 : 72;

  if (hoursSinceContact >= threshold) {
    leadsToFollowUp.push({
      json: {
        chat_id: lead.chat_id,
        first_name: lead.first_name || 'there',
        username: lead.username || '',
        status: lead.status,
        budget_min: lead.budget_min || '',
        budget_max: lead.budget_max || '',
        style_preference: lead.style_preference || '',
        artwork_type: lead.artwork_type || '',
        size_preference: lead.size_preference || '',
        space_type: lead.space_type || '',
        quantity: lead.quantity || '',
        purpose: lead.purpose || '',
        timeline: lead.timeline || '',
        notes: lead.notes || '',
        follow_up_count: followUpCount,
        follow_up_number: followUpCount + 1,
        hours_since_contact: Math.round(hoursSinceContact),
        timestamp: now.toISOString()
      }
    });
  }
}

// If no leads need follow-up, return a flag item
if (leadsToFollowUp.length === 0) {
  return [{ json: { no_leads: true, count: 0 } }];
}

return leadsToFollowUp;

// ================================================
// BUILD FOLLOW-UP PROMPT for each lead
// ================================================

const lead = $json;

const systemPrompt = `You are Noor from Fatima Habna Art Studio. Write a brief, natural follow-up message for a potential art client on Telegram.

Rules:
- Keep it to 1-2 sentences
- Sound casual and friendly, not salesy
- Reference something specific from their art preferences if available
- Do not be pushy
- Vary your approach based on the follow-up number
- Never say you are an AI
- Never use the word assist
- Detect language and respond in same language (Arabic, English, or Russian)

Follow-up styles:
Follow-up 1: Light check-in, mention something relevant to their art interest - perhaps a new piece Fatima completed in a similar style
Follow-up 2: Share an insight about a trending art style in Dubai or mention a recent installation that fits their taste
Follow-up 3: Final gentle nudge, leave the door open warmly and say no worries if the timing is not right

Respond with ONLY the message text, nothing else. No quotes around it.`;

let userPrompt = 'Follow-up #' + lead.follow_up_number + ' for ' + lead.first_name + '.\n';
userPrompt += 'Status: ' + lead.status + '\n';
if (lead.style_preference) userPrompt += 'Style preference: ' + lead.style_preference + '\n';
if (lead.artwork_type) userPrompt += 'Artwork type: ' + lead.artwork_type + '\n';
if (lead.size_preference) userPrompt += 'Size preference: ' + lead.size_preference + '\n';
if (lead.space_type) userPrompt += 'Space type: ' + lead.space_type + '\n';
if (lead.budget_min || lead.budget_max) userPrompt += 'Budget: AED ' + (lead.budget_min || '?') + ' - ' + (lead.budget_max || '?') + '\n';
if (lead.purpose) userPrompt += 'Purpose: ' + lead.purpose + '\n';
if (lead.timeline) userPrompt += 'Timeline: ' + lead.timeline + '\n';
if (lead.notes) userPrompt += 'Notes: ' + lead.notes + '\n';
userPrompt += 'Last spoke: ' + lead.hours_since_contact + ' hours ago';

const requestBody = {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  temperature: 0.8,
  max_tokens: 150
};

return {
  json: {
    ...lead,
    requestBody
  }
};

// Extract the follow-up message text from OpenAI response
const openaiResponse = $json;
const leadData = $('Build Follow-Up Prompt').first().json;

let followUpMessage = '';
try {
  followUpMessage = openaiResponse.choices[0].message.content.trim();
} catch(e) {
  followUpMessage = 'Hey ' + (leadData.first_name || 'there') + '! Just checking in - still thinking about that art piece? Let me know if I can help with anything.';
}

return {
  json: {
    chat_id: leadData.chat_id,
    first_name: leadData.first_name,
    follow_up_number: leadData.follow_up_number,
    follow_up_count: leadData.follow_up_count,
    followUpMessage,
    timestamp: leadData.timestamp
  }
};
